INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00111', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '人體研究計畫諮詢取得原住民族同意與約定商業利益及其應用辦法乃依人體研究法第15條第2項規 定所訂定。請問下列關於該辦法內容之描述，何者錯誤？', '["辦法中所謂目標群體，是指人體研究計畫預期研究之原住民族或其所屬特定群體", "辦法中對於以研究原住民族為目的者之定義，包含：「以原住民族或部落為研究內容」、「研究檢體 之採集、研究資料之搜集及分析涉及原住民族或部落」，以及「研究結果之解釋涉及原住民族或部 落」", "中央原住民族主管機關及原住民族地區之鄉（鎮、市、區）公所，應設置諮詢會代表原住民族行使 同意權與約定商業利益及其應用事項。中央諮詢會之委員，包含由中央原住民族主管機關聘用之原 住民族各族委員，以及學者專家代表", "研究計畫於諮詢及取得目標群體之同意時，研究主持人及諮詢會會議或部落會議應進行約定之事 項，包含：「研究結果所衍生商業利益之回饋機制」、「目標群體於研究過程之參與機制」，以及「研 究成果所得技術之移轉機制」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00112', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列關於山坡地保育利用條例第37條規定的敘述，何者錯誤？', '["原住民取得原住民保留地所有權，如有移轉，以原住民為限", "經中央原住民族主管機關審認符合災害之預防、災害發生時之應變及災後之復原重建用地需求，得 由政府承受私有原住民保留地", "因私人上金錢給付義務之執行事件進入法拍的原住民保留地，應由政府優先承購取得", "國有原住民保留地出租衍生之收益，得作為原住民保留地管理、原住民族地區經濟發展及基礎設施 建設、原住民族自治費用，不受國有財產法第7條規定之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00113', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '有關原住民保留地開發管理辦法中對於原住民保留地之開發利用的規範，下列敘述何者錯誤？', '["為促進原住民保留地礦業、土石、觀光遊憩、加油站、農產品集貨場倉儲設施之興建、工業資源之 開發、原住民族文化保存、醫療保健、社會福利、郵電運輸、金融服務及其他經中央主管機關核定 事業，在不妨礙原住民生計及推行原住民族行政之原則下，優先輔導原住民或原住民機構、法人或 團體開發或興辦", "原住民或原住民機構、法人或團體為前項開發或興辦，申請租用原住民保留地時，應檢具開發或興 辦計畫圖說，申請該管鄉（鎮、市、區）公所提經原住民保留地土地權利審查委員會擬具審查意見， 層報中央主管機關核准，並俟取得目的事業主管機關核准開發或興辦文件後，租用原住民保留地； 每一租期不得超過6年，期滿後得依原規定程序申請續租", "原住民機構、法人或團體以外企業或未具原住民身分者申請承租開發或興辦，應由鄉（鎮、市、區） 公所先公告30日，公告期滿無原住民或原住民機構、法人或團體申請時，始得依規定辦理申請承 租開發或興辦", "上述原住民保留地承租人，若有轉租或由他人頂替者，應終止租約收回土地，其所投資之各項設施 不予補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00114', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '原住民族委員會依原住民保留地開發管理辦法第6條規定，訂有鄉鎮市區原住民保留地土地權利審查 委員會設置要點。請問，下列關於原住民保留地土地權利審查委員會之敘述，何者錯誤？', '["其設置主任委員1人，由鄉（鎮、市、區）長兼任；委員8人至12人，由鄉（鎮、市、區）公所 聘兼之", "委員會職掌包含原住民保留地之諮商同意結果審查事項", "委員會每月開會1次，必要時得開臨時會，均由主任委員召集之", "委員對於涉及本人、其配偶或三親等內血親之議案，應自行迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00115', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依據原住民保留地禁伐補償條例，竹、木擅自拔除、採取或毀損致覆蓋率未達幾成者，則禁伐補償金 核發後，地方執行機關應撤銷禁伐補償，並命受領人按月依比例返還當年度之禁伐補償金？', '["5成", "6成", "7成", "8成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00116', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依據原住民族語言發展法，下列敘述何者錯誤？', '["原住民人口1,500人以上之非原住民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣 人員", "辦理原住民族語言能力認證應徵收規費", "原住民族地區內之街道，應設置地方通行語及傳統名稱之標示", "學校應依十二年國民基本教育本土語文課程綱要規定，提供原住民族語言課程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00117', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列關於原住民族地區資源共同管理辦法之敘述，何者錯誤？', '["中央目的事業主管機關於劃定資源治理區域前，應將計畫目的、範圍、經營管理及與當地共管事項 等計畫內容，於治理區域內鄉（鎮、市）公告閱覽及舉行公聽會，並經當地原住民族同意後，始得 劃定資源治理區域", "中央目的事業主管機關設置資源治理機關後，應遴聘（派）當地原住民族代表、資源治理機關代表 及專家學者，與原住民族建立共同管理機制", "共同管理機制之任務，包含有關資源治理機關涉及當地原住民族之中長程計畫（草案）及年度執行 計畫（草案）之研議", "共同管理機制之組成，由中央目的事業主管機關會同中央原住民族主管機關定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00118', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '有關原住民族土地與諮商事務，依據原住民族基本法第21條規定，下列敘述何者錯誤？', '["本條原住民族土地範圍，係指原住民族既有原住民保留地之意", "須諮商並取得原住民族或部落同意或參與之原住民族土地事項，包括生態保育事務", "按本條原住民得分享相關利益", "原住民族因政府或法令限制其利用土地及自然資源時，其所生之損失應受補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00119', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，下列何者得為智慧創作申請人？', '["原住民族", "部落長老", "著作人", "原住民族委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00120', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列敘述何者非屬原住民族語言發展法第1條所列之立法目的？', '["實現歷史正義", "促進原住民族語言之保存與發展", "保障原住民族語言之使用及傳承", "推動國際間原住民族語言文化之交流"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
